const baseTasks = $('Transformar Tarefas').all().map(i => i.json);
const detailsList = $input.all().map(i => i.json);

// Mescla as informações básicas de 'Transformar Tarefas' com os checklists e anotações obtidos
const enrichedTasks = baseTasks.map(task => {
  const detail = detailsList.find(d => d.id === task.plannerTaskId) || {};
  return {
    ...task,
    description: detail.description || "",
    checklist: detail.checklist || {}
  };
});

// Agrupa as tarefas pelo status operacional real
const blocked = enrichedTasks.filter(t => t.status === "Bloqueado");
const inProgress = enrichedTasks.filter(t => t.status === "Em andamento" || t.status === "Atrasado" || t.status === "Validação");
const planned = enrichedTasks.filter(t => t.isPlanejamentoSemana);
const completed = enrichedTasks.filter(t => t.status === "Concluído");

// Função para compilar o texto das tarefas omitindo o responsável para segurança
function compileTasksText(taskList) {
  if (taskList.length === 0) return "Nenhuma demanda registrada nesta categoria.";
  return taskList.map(t => {
    let text = `- Demand: "${t.atividade}" (Pilar: ${t.pilar} | Área Cliente: ${t.areaCliente})
`;
    if (t.description) {
      text += `  Anotações: ${t.description.trim()}
`;
    }
    const checklist = t.checklist || {};
    const checklistKeys = Object.keys(checklist);
    if (checklistKeys.length > 0) {
      text += `  Checklist:
`;
      checklistKeys.forEach(k => {
        const item = checklist[k];
        text += `    - [${item.isChecked ? "x" : " "}] ${item.title}
`;
      });
    }
    return text;
  }).join("\n");
}

const context = `Você é o Argos IA, o agente de inteligência autônomo do time de Governança, Segurança e Processos (GRC).
Sua missão é gerar um Parecer Executivo de alta liderança (VP Level) consolidando o status de todas as frentes de trabalho desta semana operacional.

Aqui está o status real de todas as nossas demandas:

[DEMANDAS BLOQUEADAS / IMPEDIMENTOS]
${compileTasksText(blocked)}

[DEMANDAS EM ANDAMENTO]
${compileTasksText(inProgress)}

[DEMANDAS PLANEJADAS DA SEMANA]
${compileTasksText(planned)}

[DEMANDAS CONCLUÍDAS]
${compileTasksText(completed)}

INSTRUÇÕES DO PARECER:
1. Seja estratégico, confiante e extremamente profissional (linguagem VP-level).
2. Analise os checklists das demandas em andamento e bloqueadas para apontar o andamento das frentes (ex: "Definição de papéis em GTC já concluída, aguardando suporte da alta direção...").
3. PROIBIÇÃO CRÍTICA DE NOMES PRÓPRIOS: Sob nenhuma hipótese mencione nomes próprios de pessoas/membros do time (como Leonardo, Marcos, Priscilla, Claudia, etc.) no parecer. Chame a atenção para gargalos de prazo, demandas sob foco necessário ou bloqueios operacionais referenciando puramente a iniciativa, o pilar afetado, a área cliente ou a equipe de forma genérica (ex: 'equipe de Segurança', 'responsável pela frente', 'time de sistemas').
4. Forneça uma diretriz de foco e próximos passos para a próxima semana operacional.
5. Retorne APENAS o parecer em formato HTML (use tags como <b>, <i>, <br>, <blockquote>, sem incluir tags de cabeçalho global <html> ou <body>, apenas parágrafos enriquecidos que se encaixarão em um card do Teams).
`;

return [{ json: { prompt: context } }];
